CREATE TABLE IF NOT EXISTS campus_menu_items (id uuid NOT NULL, source_id uuid NOT NULL, snapshot_id uuid, source_url text NOT NULL, university text NOT NULL, campus text NOT NULL, restaurant_name text NOT NULL, menu_date date, meal_type text NOT NULL, meal_name text NOT NULL, price_krw text NOT NULL, serving_time text NOT NULL, raw_text text NOT NULL, is_valid_menu boolean NOT NULL, name_confidence numeric NOT NULL, parser_model text NOT NULL, parser_run_id text NOT NULL, first_seen_at timestamp with time zone NOT NULL, last_seen_at timestamp with time zone NOT NULL, seen_count integer NOT NULL, created_at timestamp with time zone NOT NULL, updated_at timestamp with time zone NOT NULL);